params.script:
var memberType = $ivr.getContext('memberType');
var cls = (memberType === '企業') ? '予約_企業' : '予約_個人';
$ivr.setContext('classification', cls);
$runner.setResult(cls);

var cls = $ivr.getContext('classification');
var phonetype = $ivr.getContext('phonetype');
var cb = $ivr.getContext('callbackRequest');
if (phonetype === '携帯') {
  if (cls === '予約_個人') { $runner.setResult('予約個人_携帯'); }
  else if (cls === '予約_企業') { $runner.setResult('予約企業_携帯'); }
  else if (cls === '変更') { $runner.setResult('変更_携帯'); }
  else if (cls === 'キャンセル') { $runner.setResult('キャンセル_携帯'); }
  else if (cls === 'その他問い合わせ' && cb === 'はい') { $runner.setResult('その他_携帯'); }
  else { $runner.setResult('固定'); }
} else { $runner.setResult('固定'); }
